(function(w){"use strict";const ID="days-in-month";function leap(y){return y%400===0||(y%4===0&&y%100!==0)}function compute(x){const y=Number(x.year),m=Number(x.month);if(!Number.isInteger(y)||y<1||y>9999||!Number.isInteger(m)||m<1||m>12)return{error:"연도와 월을 올바르게 입력해 주세요."};const days=[31,leap(y)?29:28,31,30,31,30,31,31,30,31,30,31][m-1];return{days}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>연도</label><input class="hm-calc-input" inputmode="numeric" value="2026"></div><div class="hm-calc-field"><label>월</label><input class="hm-calc-input" inputmode="numeric" value="7"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">일수 계산</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const [year,month]=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({year:Number(year.value),month:Number(month.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("그 달의 일수",`${r.days}일`));});}
w.HM_CALC.register(ID,{compute,render});})(window);
